from dataclasses import dataclass
from typing import Union


@dataclass
class ASTNode:
    type: str
    value: Union[float, None] = None
    op: Union[str, None] = None
    left: Union['ASTNode', None] = None
    right: Union['ASTNode', None] = None
    operand: Union['ASTNode', None] = None


def tokenize(expression: str) -> list:
    """Tokenize the expression into numbers, operators, and parentheses."""
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c.isdigit() or c == '.':
            # Parse number
            num_str = c
            i += 1
            while i < n and (expression[i].isdigit() or expression[i] == '.'):
                num_str += expression[i]
                i += 1
            try:
                tokens.append(('number', float(num_str)))
            except ValueError:
                raise ValueError(f"Invalid number format: {num_str}")
        elif c in '+-*/()':
            tokens.append(('operator', c))
            i += 1
        else:
            raise ValueError(f"Invalid character: {c}")

    return tokens


def parse(tokens: list) -> ASTNode:
    """Parse tokens into an AST using recursive descent parsing."""
    if not tokens:
        raise ValueError("Empty expression")

    # Index to track current position
    current = [0]

    def peek(offset=0):
        if current[0] + offset < len(tokens):
            return tokens[current[0] + offset]
        return None

    def consume():
        token = peek()
        current[0] += 1
        return token

    def parse_expression():
        return parse_additive()

    def parse_additive():
        node = parse_multiplicative()

        while peek() and peek()[1] in ('+', '-'):
            op_token = consume()
            right = parse_multiplicative()
            node = ASTNode(type='binop', op=op_token[1], left=node, right=right)

        return node

    def parse_multiplicative():
        node = parse_unary()

        while peek() and peek()[1] in ('*', '/'):
            op_token = consume()
            right = parse_unary()
            node = ASTNode(type='binop', op=op_token[1], left=node, right=right)

        return node

    def parse_unary():
        # Check for unary minus
        if peek() and peek()[1] == '-':
            op_token = consume()
            operand = parse_primary()
            return ASTNode(type='unary', op=op_token[1], operand=operand)

        return parse_primary()

    def parse_primary():
        token = consume()

        if token[0] == 'number':
            return ASTNode(type='number', value=token[1])
        elif token[1] == '(':
            node = parse_expression()
            if not peek() or peek()[1] != ')':
                raise ValueError("Unmatched parentheses")
            consume()  # consume ')'
            return node
        else:
            raise ValueError(f"Unexpected token: {token[1]}")

    return parse_expression()


def parse(expression: str) -> ASTNode:
    """Parse a string expression into an AST."""
    tokens = tokenize(expression)
    try:
        return parse(tokens)
    except Exception as e:
        if isinstance(e, ValueError):
            raise
        raise ValueError(f"Parse error: {str(e)}")


def evaluate(node: ASTNode) -> float:
    """Evaluate an AST node to a numeric result."""
    if node.type == 'number':
        return node.value
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == 'unary':
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val
    else:
        raise ValueError(f"Unknown node type: {node.type}")


# Test cases
if __name__ == "__main__":
    test_cases = [
        "5",
        "2 + 3",
        "2 * 3 + 4",
        "2 + 3 * 4",
        "(2 + 3) * 4",
        "-5",
        "-(3 + 2)",
        "10 / 2",
        "10 / 0",
        "2 * (3 + 4) - 5 / 2",
        "   ",
        "2 +",
        "(2 + 3",
        "2 + abc"
    ]

    for expr in test_cases:
        print(f"\nTesting: {expr}")
        try:
            ast = parse(expr)
            result = evaluate(ast)
            print(f"  Result: {result}")
            print(f"  AST: {ast}")
        except ValueError as e:
            print(f"  Error: {e}")
        except ZeroDivisionError as e:
            print(f"  Error: {e}")
